13: /// or <see cref="DisplayNameAttribute"/> if present, or falling back to the property name.
14: /// </summary>
15: /// <typeparam name="TValue">The type of the field.</typeparam>
16: public class DisplayName<TValue> : IComponent
17: {
18: 
19:     private RenderHandle _renderHandle;
20:     private Expression<Func<TValue>>? _previousFieldAccessor;
21:     private string? _displayName;
22: 
23:     /// <summary>
24:     /// Specifies the field for which the display name should be shown.
25:     /// </summary>
26:     [Parameter, EditorRequired]
27:     public Expression<Func<TValue>>? For { get; set; }
28:     /// <inheritdoc />
29:     void IComponent.Attach(RenderHandle renderHandle)
30:     {
31:         _renderHandle = renderHandle;
32:     }
33: 
34:     /// <inheritdoc />
35:     Task IComponent.SetParametersAsync(ParameterView parameters)
36:     {
37:         parameters.SetParameterProperties(this);
38: 
39:         if (For is null)
40:         {
41:             throw new InvalidOperationException($"{GetType()} requires a value for the " +
42:                 $"{nameof(For)} parameter.");
43:         }
44: 
45:         // Only recalculate if the expression changed
46:         if (For != _previousFieldAccessor)
47:         {
48:             var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
49: 
50:             if (newDisplayName != _displayName)
51:             {
52:                 _displayName = newDisplayName;
53:                 _renderHandle.Render(BuildRenderTree);
54:             }
55: 
56:             _previousFieldAccessor = For;
57:         }
58: 
59:         return Task.CompletedTask;
60:     }
61: 
